using System.ComponentModel;
using System.Net;
using System.Text;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool state ---
var notebook = new ResearchNotebook();

// --- Define tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchAsync(query);
        },
        "web_search",
        "Searches the web for the given query and returns a list of result snippets with titles and URLs. Use this to find information about a research topic."),

    AIFunctionFactory.Create(
        ([Description("A short title for the note")] string title,
         [Description("The content of the note to save")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        "save_note",
        "Saves a research note to the notebook. Use this to record key findings, facts, or insights discovered during research."),

    AIFunctionFactory.Create(
        () =>
        {
            return notebook.GetAllNotes();
        },
        "read_notes",
        "Reads all previously saved research notes. Use this to review what has been recorded so far before writing a summary."),
};

// --- Create the agent ---
var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var agent = new ChatClientAgent(chatClient, agentOptions, tools: tools);

// --- System instructions ---
const string systemInstructions = """
    You are a research assistant. Your job is to thoroughly research a topic the user gives you.

    Follow this workflow:
    1. Break the topic into 2-3 specific search queries.
    2. Use the web_search tool for each query.
    3. Use the save_note tool to record key findings from each search (include source URLs).
    4. Use read_notes to review everything you have gathered.
    5. Provide a well-structured summary to the user with sections, key facts, and source citations.

    Be thorough but concise. Always cite your sources.
    """;

// --- Main loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        Research Agent (MAF)          ║");
Console.WriteLine("║  Type a topic to research, or 'q'   ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic > ");
    Console.ResetColor();

    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("q", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

    notebook.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemInstructions),
        new(ChatRole.User, $"Research this topic: {topic}"),
    };

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching... (the agent will search the web and take notes)");
    Console.ResetColor();

    try
    {
        var runOptions = new ChatClientAgentRunOptions(new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
        });

        await foreach (var update in agent.RunStreamingAsync(messages, options: runOptions))
        {
            if (!string.IsNullOrEmpty(update.Text))
            {
                Console.Write(update.Text);
            }
        }

        Console.WriteLine();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

Console.WriteLine("Goodbye!");
return;

// --- Web search implementation ---
static async Task<string> WebSearchAsync(string query)
{
    // Uses the DuckDuckGo HTML endpoint for a lightweight, key-free search.
    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var encodedQuery = WebUtility.UrlEncode(query);
    var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";

    try
    {
        var html = await http.GetStringAsync(url);
        return ParseDuckDuckGoResults(html, maxResults: 5);
    }
    catch (Exception ex)
    {
        return $"Search failed: {ex.Message}. Please try a different query.";
    }
}

static string ParseDuckDuckGoResults(string html, int maxResults)
{
    // Simple HTML parsing for DuckDuckGo result snippets.
    var results = new StringBuilder();
    var resultCount = 0;

    var searchIndex = 0;
    while (resultCount < maxResults)
    {
        // Find result blocks marked by class="result__a"
        var titleStart = html.IndexOf("class=\"result__a\"", searchIndex, StringComparison.Ordinal);
        if (titleStart < 0)
        {
            break;
        }

        // Extract title
        var tagClose = html.IndexOf('>', titleStart);
        var tagEnd = html.IndexOf("</a>", tagClose, StringComparison.Ordinal);
        if (tagClose < 0 || tagEnd < 0)
        {
            break;
        }

        var title = StripHtmlTags(html[(tagClose + 1)..tagEnd]).Trim();

        // Extract URL from href
        var hrefSearch = html.LastIndexOf("href=\"", titleStart, titleStart - Math.Max(0, titleStart - 200), StringComparison.Ordinal);
        var resultUrl = "";
        if (hrefSearch >= 0)
        {
            var hrefStart = hrefSearch + 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd > hrefStart)
            {
                resultUrl = html[hrefStart..hrefEnd];
                if (resultUrl.StartsWith("//duckduckgo.com/l/?uddg=", StringComparison.Ordinal))
                {
                    var uddgStart = resultUrl.IndexOf("uddg=", StringComparison.Ordinal) + 5;
                    var uddgEnd = resultUrl.IndexOf('&', uddgStart);
                    resultUrl = WebUtility.UrlDecode(
                        uddgEnd > 0 ? resultUrl[uddgStart..uddgEnd] : resultUrl[uddgStart..]);
                }
            }
        }

        // Extract snippet
        var snippetStart = html.IndexOf("class=\"result__snippet\"", tagEnd, StringComparison.Ordinal);
        var snippet = "";
        if (snippetStart >= 0 && snippetStart < tagEnd + 1000)
        {
            var snippetTagClose = html.IndexOf('>', snippetStart);
            var snippetTagEnd = html.IndexOf("</a>", snippetTagClose, StringComparison.Ordinal);
            if (snippetTagClose >= 0 && snippetTagEnd >= 0)
            {
                snippet = StripHtmlTags(html[(snippetTagClose + 1)..snippetTagEnd]).Trim();
            }
        }

        if (!string.IsNullOrWhiteSpace(title))
        {
            resultCount++;
            results.AppendLine($"[{resultCount}] {title}");
            if (!string.IsNullOrEmpty(resultUrl))
            {
                results.AppendLine($"    URL: {resultUrl}");
            }

            if (!string.IsNullOrEmpty(snippet))
            {
                results.AppendLine($"    {snippet}");
            }

            results.AppendLine();
        }

        searchIndex = tagEnd + 1;
    }

    return resultCount > 0
        ? results.ToString()
        : "No results found. Try rephrasing your search query.";
}

static string StripHtmlTags(string html)
{
    var sb = new StringBuilder(html.Length);
    var inTag = false;
    foreach (var ch in html)
    {
        switch (ch)
        {
            case '<':
                inTag = true;
                break;
            case '>':
                inTag = false;
                break;
            default:
                if (!inTag)
                {
                    sb.Append(ch);
                }

                break;
        }
    }

    return WebUtility.HtmlDecode(sb.ToString());
}

// --- Research notebook ---
sealed class ResearchNotebook
{
    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];

    public void AddNote(string title, string content)
    {
        _notes.Add((title, content, DateTime.UtcNow));
    }

    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes recorded yet.";
        }

        var sb = new StringBuilder();
        for (var i = 0; i < _notes.Count; i++)
        {
            var (title, content, timestamp) = _notes[i];
            sb.AppendLine($"--- Note {i + 1}: {title} ({timestamp:HH:mm:ss UTC}) ---");
            sb.AppendLine(content);
            sb.AppendLine();
        }

        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

