    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running this app.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient via MEAI abstraction ---
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tool state ---
var notebook = new ResearchNotebook();

// --- Define tools ---
var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearchAsync(query);
        },
        "web_search",
        "Searches the web for the given query and returns a list of result snippets with titles and URLs. Use this to find information about a research topic."),

    AIFunctionFactory.Create(
        ([Description("A short title for the note")] string title,
         [Description("The content of the note to save")] string content) =>
        {
            notebook.AddNote(title, content);
            return $"Note saved: \"{title}\" ({content.Length} chars)";
        },
        "save_note",
        "Saves a research note to the notebook. Use this to record key findings, facts, or insights discovered during research."),

    AIFunctionFactory.Create(
        () =>
        {
            return notebook.GetAllNotes();
        },
        "read_notes",
        "Reads all previously saved research notes. Use this to review what has been recorded so far before writing a summary."),
};

