var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An AI agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
    },
};

var agent = new ChatClientAgent(chatClient, agentOptions, tools: tools);

// --- System instructions ---
const string systemInstructions = """
    You are a research assistant. Your job is to thoroughly research a topic the user gives you.

    Follow this workflow:
    1. Break the topic into 2-3 specific search queries.
    2. Use the web_search tool for each query.
    3. Use the save_note tool to record key findings from each search (include source URLs).
    4. Use read_notes to review everything you have gathered.
    5. Provide a well-structured summary to the user with sections, key facts, and source citations.

    Be thorough but concise. Always cite your sources.
    """;

