while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("Research topic > ");
    Console.ResetColor();

    var topic = Console.ReadLine();
    if (string.IsNullOrWhiteSpace(topic) || topic.Equals("q", StringComparison.OrdinalIgnoreCase))
    {
        break;
    }

