+    http.DefaultRequestHeaders.UserAgent.ParseAdd(
+        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");
+
+    var encodedQuery = WebUtility.UrlEncode(query);
+    var url = $"https://html.duckduckgo.com/html/?q={encodedQuery}";
+
+    try
+    {
+        var html = await http.GetStringAsync(url);
+        return ParseDuckDuckGoResults(html, maxResults: 5);
+    }
+    catch (Exception ex)
+    {
+        return $"Search failed: {ex.Message}. Please try a different query.";
+    }
+}
+
+static string ParseDuckDuckGoResults(string html, int maxResults)
+{
+    // Simple HTML parsing for DuckDuckGo result snippets.
+    var results = new StringBuilder();
+    var resultCount = 0;
+
+    var searchIndex = 0;
+    while (resultCount < maxResults)
+    {
+        // Find result blocks marked by class="result__a"
+        var titleStart = html.IndexOf("class=\"result__a\"", searchIndex, StringComparison.Ordinal);
+        if (titleStart < 0)
+        {
+            break;
+        }
+
+        // Extract title
+        var tagClose = html.IndexOf('>', titleStart);
+        var tagEnd = html.IndexOf("</a>", tagClose, StringComparison.Ordinal);
+        if (tagClose < 0 || tagEnd < 0)
+        {
+            break;
+        }
+
+        var title = StripHtmlTags(html[(tagClose + 1)..tagEnd]).Trim();
+
+        // Extract URL from href
+        var hrefSearch = html.LastIndexOf("href=\"", titleStart, titleStart - Math.Max(0, titleStart - 200), StringComparison.Ordinal);
+        var resultUrl = "";
+        if (hrefSearch >= 0)
+        {
+            var hrefStart = hrefSearch + 6;
+            var hrefEnd = html.IndexOf('"', hrefStart);
+            if (hrefEnd > hrefStart)
+            {
+                resultUrl = html[hrefStart..hrefEnd];
+                if (resultUrl.StartsWith("//duckduckgo.com/l/?uddg=", StringComparison.Ordinal))
+                {
+                    var uddgStart = resultUrl.IndexOf("uddg=", StringComparison.Ordinal) + 5;
+                    var uddgEnd = resultUrl.IndexOf('&', uddgStart);
+                    resultUrl = WebUtility.UrlDecode(
+                        uddgEnd > 0 ? resultUrl[uddgStart..uddgEnd] : resultUrl[uddgStart..]);
+                }
+            }
+        }
+
+        // Extract snippet
+        var snippetStart = html.IndexOf("class=\"result__snippet\"", tagEnd, StringComparison.Ordinal);
+        var snippet = "";
+        if (snippetStart >= 0 && snippetStart < tagEnd + 1000)
+        {
+            var snippetTagClose = html.IndexOf('>', snippetStart);
+            var snippetTagEnd = html.IndexOf("</a>", snippetTagClose, StringComparison.Ordinal);
+            if (snippetTagClose >= 0 && snippetTagEnd >= 0)
+            {
+                snippet = StripHtmlTags(html[(snippetTagClose + 1)..snippetTagEnd]).Trim();
+            }
+        }
+
+        if (!string.IsNullOrWhiteSpace(title))
+        {
+            resultCount++;
+            results.AppendLine($"[{resultCount}] {title}");
+            if (!string.IsNullOrEmpty(resultUrl))
+            {
+                results.AppendLine($"    URL: {resultUrl}");
+            }
+
+            if (!string.IsNullOrEmpty(snippet))
+            {
+                results.AppendLine($"    {snippet}");
+            }
+
+            results.AppendLine();
+        }
+
+        searchIndex = tagEnd + 1;
+    }
+
+    return resultCount > 0
+        ? results.ToString()
+        : "No results found. Try rephrasing your search query.";
+}
+
+static string StripHtmlTags(string html)
+{
+    var sb = new StringBuilder(html.Length);
+    var inTag = false;
+    foreach (var ch in html)
+    {
+        switch (ch)
+        {
+            case '<':
+                inTag = true;
+                break;
+            case '>':
+                inTag = false;
+                break;
+            default:
+                if (!inTag)
+                {
+                    sb.Append(ch);
+                }
+
+                break;
+        }
+    }
+
+    return WebUtility.HtmlDecode(sb.ToString());
+}
+
+// --- Research notebook ---
+sealed class ResearchNotebook
+{
+    private readonly List<(string Title, string Content, DateTime Timestamp)> _notes = [];
+
+    public void AddNote(string title, string content)
+    {
+        _notes.Add((title, content, DateTime.UtcNow));
+    }
+
+    public string GetAllNotes()
+    {
+        if (_notes.Count == 0)
+        {
+            return "No notes recorded yet.";
+        }
+
+        var sb = new StringBuilder();
+        for (var i = 0; i < _notes.Count; i++)
+        {
+            var (title, content, timestamp) = _notes[i];
+            sb.AppendLine($"--- Note {i + 1}: {title} ({timestamp:HH:mm:ss UTC}) ---");
+            sb.AppendLine(content);
+            sb.AppendLine();
+        }
+
+        return sb.ToString();
+    }
+
+    public void Clear() => _notes.Clear();
+}

